## Page Object Model - Deep Dive

### Core Principles

The Page Object Model pattern rests on several key principles:

1. **Encapsulation**: Hide the internal structure of the page behind a public API
2. **Single Responsibility**: Each page object manages one page or component
3. **DRY (Don't Repeat Yourself)**: Define locators and interactions once
4. **Readability**: Tests should read like user scenarios

### Basic Page Object Implementation

```python
from playwright.sync_api import Page, expect


class LoginPage:
    URL = '/login'

    def __init__(self, page: Page):
        self.page = page
        # Define locators in constructor
        self.email_input = page.get_by_label('Email address')
        self.password_input = page.get_by_label('Password')
        self.remember_checkbox = page.get_by_label('Remember me')
        self.submit_button = page.get_by_role('button', name='Sign in')
        self.forgot_password_link = page.get_by_role('link', name='Forgot password?')
        self.error_alert = page.get_by_role('alert')
        self.signup_link = page.get_by_role('link', name='Create account')

    def goto(self):
        self.page.goto(self.URL)
        return self

    def login(self, email: str, password: str, remember: bool = False):
        self.email_input.fill(email)
        self.password_input.fill(password)
        if remember:
            self.remember_checkbox.check()
        self.submit_button.click()
        return DashboardPage(self.page)

    def login_expecting_error(self, email: str, password: str) -> str:
        self.email_input.fill(email)
        self.password_input.fill(password)
        self.submit_button.click()
        expect(self.error_alert).to_be_visible()
        return self.error_alert.text_content()

    def navigate_to_signup(self):
        self.signup_link.click()
        return SignupPage(self.page)

    def navigate_to_forgot_password(self):
        self.forgot_password_link.click()
        return ForgotPasswordPage(self.page)
```

### Component-Based Page Objects

For large applications, decompose pages into reusable components:

```python
class HeaderComponent:
    def __init__(self, page: Page):
        self.page = page
        self.container = page.locator('header')
        self.logo = self.container.get_by_role('link', name='Home')
        self.search_input = self.container.get_by_placeholder('Search...')
        self.user_menu = self.container.get_by_test_id('user-menu')
        self.notifications = self.container.get_by_test_id('notifications')

    def search(self, query: str):
        self.search_input.fill(query)
        self.search_input.press('Enter')
        return SearchResultsPage(self.page)

    def open_user_menu(self):
        self.user_menu.click()

    def logout(self):
        self.open_user_menu()
        self.page.get_by_role('menuitem', name='Logout').click()
        return LoginPage(self.page)

    def get_notification_count(self) -> int:
        badge = self.notifications.locator('.badge')
        if badge.is_visible():
            return int(badge.text_content())
        return 0


class SidebarComponent:
    def __init__(self, page: Page):
        self.page = page
        self.container = page.locator('aside.sidebar')

    def navigate_to(self, section: str):
        self.container.get_by_role('link', name=section).click()

    def is_section_active(self, section: str) -> bool:
        link = self.container.get_by_role('link', name=section)
        return 'active' in (link.get_attribute('class') or '')


class DataTableComponent:
    def __init__(self, page: Page, container_locator):
        self.page = page
        self.container = container_locator
        self.rows = self.container.get_by_role('row')
        self.headers = self.container.locator('th')

    def get_row_count(self) -> int:
        return self.rows.count() - 1  # Subtract header row

    def get_row_by_text(self, text: str):
        return self.rows.filter(has_text=text)

    def sort_by_column(self, column_name: str):
        self.headers.filter(has_text=column_name).click()

    def get_cell_value(self, row_index: int, column_index: int) -> str:
        return self.rows.nth(row_index + 1).locator('td').nth(column_index).text_content()


class DashboardPage:
    def __init__(self, page: Page):
        self.page = page
        self.header = HeaderComponent(page)     # Composed components
        self.sidebar = SidebarComponent(page)
        self.stats_table = DataTableComponent(page, page.locator('#stats-table'))
        self.heading = page.get_by_role('heading', level=1)

    def goto(self):
        self.page.goto('/dashboard')
        return self
```

### Base Page Object with Common Functionality

```python
class BasePage:
    """Base class for all page objects with shared functionality."""

    def __init__(self, page: Page):
        self.page = page
        self.header = HeaderComponent(page)

    def get_current_url(self) -> str:
        return self.page.url

    def get_page_title(self) -> str:
        return self.page.title()

    def take_screenshot(self, name: str):
        self.page.screenshot(path=f'screenshots/{name}.png')

    def wait_for_page_load(self):
        self.page.wait_for_load_state('networkidle')

    def scroll_to_bottom(self):
        self.page.evaluate('window.scrollTo(0, document.body.scrollHeight)')


class ProductListPage(BasePage):
    def __init__(self, page: Page):
        super().__init__(page)
        self.products = page.locator('.product-card')
        self.filter_sidebar = FilterComponent(page)
        self.sort_dropdown = page.get_by_label('Sort by')
```

### Using Fixtures for Dependency Injection

```python
# conftest.py
import pytest
from playwright.sync_api import Page
from pages.login_page import LoginPage
from pages.dashboard_page import DashboardPage

@pytest.fixture
def login_page(page: Page):
    login = LoginPage(page)
    login.goto()
    return login

@pytest.fixture
def authenticated_page(browser, auth_state):
    context = browser.new_context(storage_state=auth_state)
    page = context.new_page()
    yield page
    context.close()

@pytest.fixture
def dashboard_page(authenticated_page):
    dashboard = DashboardPage(authenticated_page)
    dashboard.goto()
    return dashboard
```

```python
# test_dashboard.py
def test_dashboard_shows_stats(dashboard_page):
    expect(dashboard_page.heading).to_have_text('Dashboard')
    assert dashboard_page.stats_table.get_row_count() > 0

def test_search_from_dashboard(dashboard_page):
    results = dashboard_page.header.search('test query')
    expect(results.result_count).to_have_text(re.compile(r'\d+ results'))

def test_logout(dashboard_page):
    login = dashboard_page.header.logout()
    expect(login.page).to_have_url('**/login')
```

### Playwright's Built-in POM Support (JavaScript)

Playwright's JavaScript test runner has built-in fixture support for POM:

```typescript
// fixtures.ts
import { test as base } from '@playwright/test';
import { LoginPage } from './pages/login-page';
import { DashboardPage } from './pages/dashboard-page';

type MyFixtures = {
    loginPage: LoginPage;
    dashboardPage: DashboardPage;
};

export const test = base.extend<MyFixtures>({
    loginPage: async ({ page }, use) => {
        const loginPage = new LoginPage(page);
        await loginPage.goto();
        await use(loginPage);
    },
    dashboardPage: async ({ page }, use) => {
        const dashboardPage = new DashboardPage(page);
        await dashboardPage.goto();
        await use(dashboardPage);
    }
});

export { expect } from '@playwright/test';
```

