## Page Object Model - Tips & Tricks

### 1. Use Property Decorators for Derived Data

```python
class ProductPage:
    def __init__(self, page):
        self.page = page

    @property
    def price(self) -> float:
        text = self.page.locator('.price').text_content()
        return float(text.replace('$', '').replace(',', ''))

    @property
    def is_in_stock(self) -> bool:
        return self.page.locator('.stock-status').text_content() == 'In Stock'

    @property
    def rating(self) -> float:
        stars = self.page.locator('.star.filled').count()
        return float(stars)

# Clean usage
assert product_page.price == 29.99
assert product_page.is_in_stock
assert product_page.rating >= 4.0
```

### 2. Create Factory Methods for Complex Setup

```python
class OrderPage:
    @classmethod
    def create_with_items(cls, page, items):
        """Create an order page with pre-filled items via API."""
        # Use API to set up test data quickly
        for item in items:
            page.request.post('/api/cart/add', data=item)
        page.goto('/checkout')
        return cls(page)

# Usage
order = OrderPage.create_with_items(page, [
    {'product_id': 1, 'quantity': 2},
    {'product_id': 5, 'quantity': 1}
])
```

### 3. Add `__repr__` for Better Debugging

```python
class LoginPage:
    def __repr__(self):
        return f'LoginPage(url={self.page.url})'

# When printed in error messages:
# AssertionError: Expected LoginPage(url=https://example.com/login) to redirect
```

### 4. Create a Page Object Generator Script

Automate page object creation with a helper script:

```python
# generate_page.py
def generate_page_object(name, url, elements):
    code = f'''from playwright.sync_api import Page, Locator

class {name}:
    URL = '{url}'

    def __init__(self, page: Page):
        self.page = page
'''
    for elem_name, locator in elements.items():
        code += f"        self.{elem_name} = page.{locator}\n"

    code += '''
    def goto(self):
        self.page.goto(self.URL)
        return self
'''
    return code
```

### 5. Use Context Managers for Temporary States

```python
class AdminPage:
    from contextlib import contextmanager

    @contextmanager
    def impersonate_user(self, username):
        """Temporarily impersonate another user."""
        self.page.get_by_test_id('impersonate').click()
        self.page.get_by_label('Username').fill(username)
        self.page.get_by_role('button', name='Impersonate').click()
        try:
            yield  # Test runs as impersonated user
        finally:
            self.page.get_by_test_id('stop-impersonation').click()

# Usage
with admin_page.impersonate_user('john'):
    expect(page.get_by_text('Viewing as john')).to_be_visible()
    # ... test as john ...
# Back to admin after context exits
```

### 6. Lazy Locator Initialization

For dynamic elements that do not exist at page load, use methods instead of properties:

```python
class DynamicPage:
    def __init__(self, page):
        self.page = page

    def get_notification(self, index: int):
        """Get notification by index (they load dynamically)."""
        return self.page.locator('.notification').nth(index)

    def get_tab_content(self, tab_name: str):
        """Get content panel for a specific tab."""
        return self.page.locator(f'[data-tab="{tab_name}"] .content')
```

### 7. Combine API Setup with UI Verification

```python
class UserManagementPage:
    def create_user_via_api(self, user_data):
        """Create user via API for speed, then verify in UI."""
        self.page.request.post('/api/users', data=user_data)
        self.page.reload()
        return self

    def verify_user_exists(self, username):
        expect(self.users_table.filter(has_text=username)).to_be_visible()
```

### 8. Map Complex Workflows Across Page Objects

```python
class PurchaseWorkflow:
    """Orchestrates the entire purchase flow across multiple pages."""

    def __init__(self, page):
        self.page = page

    def complete_purchase(self, product, address, card):
        product_page = ProductPage(self.page)
        product_page.goto(product['url'])

        cart = product_page.add_to_cart(product['quantity'])
        checkout = cart.proceed_to_checkout()
        checkout.fill_shipping_address(address)
        checkout.fill_payment_info(card)
        confirmation = checkout.place_order()

        return confirmation.get_order_number()
```

### 9. Version Your Page Objects with the Application

Keep page objects in the same repository as the application code, or at least version them together. This prevents drift between the UI and the test infrastructure.

### 10. Test Your Page Objects

Write a small set of smoke tests specifically for page object validity to catch locator drift early.
